    'Resolution', 240);
savefig(figureHandle, fullfile(outputRoot, 'grant_lar_trace_1500_2500s_unitary_compound_peaks.fig'));
close(figureHandle);
end

function [windowStartSec, windowEndSec] = LF_chooseLongScaleWindow(fileContext, trialBouts)
settlingEndSec = 300;
windowLengthSec = 3600;
stepSec = 60;
latestStartSec = max(fileContext.timeSec) - windowLengthSec;
if latestStartSec <= settlingEndSec
    windowStartSec = min(max(settlingEndSec, min(fileContext.timeSec)), max(fileContext.timeSec));
    windowEndSec = max(fileContext.timeSec);
    return;
end

startTimes = settlingEndSec:stepSec:latestStartSec;
bestScore = -Inf;
windowStartSec = startTimes(1);
windowEndSec = windowStartSec + windowLengthSec;
for startIndex = 1:numel(startTimes)
    candidateStartSec = startTimes(startIndex);
    candidateEndSec = candidateStartSec + windowLengthSec;
    boutMask = trialBouts.onsetTimeSec >= candidateStartSec & trialBouts.onsetTimeSec <= candidateEndSec;
    candidateBouts = trialBouts(boutMask, :);
    nUnitary = sum(candidateBouts.isUnitaryBout);
    nCompound = sum(candidateBouts.isCompoundBout);
    if nUnitary < 5 || nCompound < 5
        continue;
    end

    signalMask = fileContext.timeSec >= candidateStartSec & fileContext.timeSec <= candidateEndSec;
    p99 = prctile(fileContext.motionEnvelope(signalMask), 99);
    p999 = prctile(fileContext.motionEnvelope(signalMask), 99.9);
    balanceScore = min(nUnitary, nCompound);
    countScore = 0.02 .* (nUnitary + nCompound);
    grossMovementPenalty = max(0, p999 - 0.12) .* 400 + max(0, p99 - 0.05) .* 100;
    score = balanceScore + countScore - grossMovementPenalty;
    if score > bestScore
        bestScore = score;
        windowStartSec = candidateStartSec;
        windowEndSec = candidateEndSec;
    end
end
end

function LF_addAbovePeakMarkers(ax, fileContext, boutRows, subpeakTable, windowStartSec, ...
    markerOffset, yLimitTop, colorValue, displayName)
for rowIndex = 1:height(boutRows)
    row = boutRows(rowIndex, :);
    subRows = subpeakTable(string(subpeakTable.fileName) == string(row.fileName) & ...
        subpeakTable.dominantPeakIndex == row.dominantPeakIndex, :);
    for subIndex = 1:height(subRows)
        peakX = fileContext.timeSec(subRows.subpeakIndex(subIndex)) - windowStartSec;
        peakY = fileContext.motionEnvelope(subRows.subpeakIndex(subIndex));
        markerY = min(yLimitTop .* 0.96, peakY + markerOffset);
        if rowIndex == 1 && subIndex == 1
            markerVisibility = 'on';
        else
            markerVisibility = 'off';
        end
        plot(ax, peakX, markerY, '.', 'Color', colorValue, 'MarkerSize', 16, ...
            'DisplayName', displayName, 'HandleVisibility', markerVisibility);
    end
end
end

function LF_addPeakMarkers(ax, fileContext, boutRows, subpeakTable, windowStartSec, colorValue, displayName)
for rowIndex = 1:height(boutRows)
    row = boutRows(rowIndex, :);
    subRows = subpeakTable(string(subpeakTable.fileName) == string(row.fileName) & ...
        subpeakTable.dominantPeakIndex == row.dominantPeakIndex, :);
    for subIndex = 1:height(subRows)
        peakX = fileContext.timeSec(subRows.subpeakIndex(subIndex)) - windowStartSec;
        peakY = fileContext.motionEnvelope(subRows.subpeakIndex(subIndex));
        if rowIndex == 1 && subIndex == 1
            markerVisibility = 'on';
        else
            markerVisibility = 'off';
        end
        plot(ax, peakX, peakY, 'o', 'MarkerFaceColor', colorValue, ...
            'MarkerEdgeColor', 'w', 'MarkerSize', 7, ...
            'DisplayName', displayName, 'HandleVisibility', markerVisibility);
    end
end
end

function [exampleWindow, windowStartSec, windowEndSec] = LF_choosePeakOnlyWindow(fileContext, trialBouts)
settlingEndSec = 300;
windowLengthSec = 60;
stepSec = 5;
eligibleBouts = trialBouts(trialBouts.onsetTimeSec >= settlingEndSec, :);
if height(eligibleBouts) >= 5
    trialBouts = eligibleBouts;
end

startTimes = min(trialBouts.onsetTimeSec):stepSec:(max(trialBouts.onsetTimeSec) - windowLengthSec);
if isempty(startTimes)
    exampleWindow = trialBouts;
    windowStartSec = max(min(trialBouts.onsetTimeSec) - 5, min(fileContext.timeSec));
    windowEndSec = min(windowStartSec + windowLengthSec, max(fileContext.timeSec));
    return;
end

bestScore = -Inf;
bestMask = true(height(trialBouts), 1);
bestWindowStartSec = startTimes(1);
for startIndex = 1:numel(startTimes)
    windowStart = startTimes(startIndex);
    windowEnd = windowStart + windowLengthSec;
    mask = trialBouts.onsetTimeSec >= windowStart & trialBouts.onsetTimeSec <= windowEnd;
    windowRows = trialBouts(mask, :);
    if height(windowRows) < 4
        continue;
    end

    nUnitary = sum(windowRows.isUnitaryBout);
    nCompound = sum(windowRows.isCompoundBout);
    if nUnitary < 1 || nCompound < 1
        continue;
    end

    signalMask = fileContext.timeSec >= windowStart & fileContext.timeSec <= windowEnd;
    windowMax = max(fileContext.motionEnvelope(signalMask), [], 'omitnan');
    windowRange = range(fileContext.motionEnvelope(signalMask), 'omitnan');
    balanceScore = min(nUnitary, nCompound);
    countScore = nUnitary + nCompound;
    amplitudePenalty = max(0, windowMax - 0.08) .* 120;
    flatPenalty = max(0, 0.02 - windowRange) .* 100;
    score = balanceScore .* 12 + countScore - amplitudePenalty - flatPenalty;

    if score > bestScore
        bestScore = score;
        bestMask = mask;
        bestWindowStartSec = windowStart;
    end
end

exampleWindow = trialBouts(bestMask, :);
windowStartSec = bestWindowStartSec;
windowEndSec = min(bestWindowStartSec + windowLengthSec, max(fileContext.timeSec));
end

function LF_addBoutMarkers(ax, fileContext, boutTable, subpeakTable, useMinutes, timeOffsetSec, showSubpeaks)
if nargin < 6
    timeOffsetSec = 0;
end
if nargin < 7
    showSubpeaks = true;
end

unitaryRows = boutTable(boutTable.isUnitaryBout, :);
compoundRows = boutTable(boutTable.isCompoundBout, :);
unitaryColor = [0.05 0.35 0.70];
compoundColor = [0.80 0.30 0.10];

LF_plotRows(unitaryRows, unitaryColor, 'unitary onset', 'unitary peak');
LF_plotRows(compoundRows, compoundColor, 'compound onset', 'compound subpeaks');

    function LF_plotRows(rows, colorValue, onsetName, peakName)
        for rowIndex = 1:height(rows)
            row = rows(rowIndex, :);
            if useMinutes
                onsetX = fileContext.timeSec(row.onsetIndex) ./ 60;
            else
                onsetX = fileContext.timeSec(row.onsetIndex) - timeOffsetSec;
            end
            onsetY = fileContext.motionEnvelope(row.onsetIndex);
            if rowIndex == 1
                onsetVisibility = 'on';
            else
                onsetVisibility = 'off';
            end
            plot(ax, onsetX, onsetY, 'v', 'MarkerFaceColor', colorValue, ...
                'MarkerEdgeColor', colorValue, 'MarkerSize', 5, ...
                'DisplayName', onsetName, 'HandleVisibility', onsetVisibility);

            if showSubpeaks
                subRows = subpeakTable(string(subpeakTable.fileName) == string(row.fileName) & ...
                    subpeakTable.dominantPeakIndex == row.dominantPeakIndex, :);
                for subIndex = 1:height(subRows)
                    if useMinutes
                        peakX = fileContext.timeSec(subRows.subpeakIndex(subIndex)) ./ 60;
                    else
                        peakX = fileContext.timeSec(subRows.subpeakIndex(subIndex)) - timeOffsetSec;
                    end
                    peakY = fileContext.motionEnvelope(subRows.subpeakIndex(subIndex));
                    if rowIndex == 1 && subIndex == 1
                        peakVisibility = 'on';
                    else
                        peakVisibility = 'off';
                    end
                    plot(ax, peakX, peakY, 'o', 'MarkerFaceColor', colorValue, ...
                        'MarkerEdgeColor', 'w', 'MarkerSize', 5, ...
                        'DisplayName', peakName, 'HandleVisibility', peakVisibility);
                end
            end
        end
    end
end

function bestWindow = LF_chooseDetailedWindow(trialBouts)
windowLengthSec = 30;
stepSec = 3;
settlingEndSec = 300;
eligibleBouts = trialBouts(trialBouts.onsetTimeSec >= settlingEndSec, :);
if height(eligibleBouts) >= 5
    trialBouts = eligibleBouts;
end
startTimes = min(trialBouts.onsetTimeSec):stepSec:(max(trialBouts.onsetTimeSec) - windowLengthSec);
if isempty(startTimes)
    bestWindow = trialBouts;
    return;
end

bestScore = -Inf;
bestMask = true(height(trialBouts), 1);
for startIndex = 1:numel(startTimes)
    windowStart = startTimes(startIndex);
    windowEnd = windowStart + windowLengthSec;
    mask = trialBouts.onsetTimeSec >= windowStart & trialBouts.onsetTimeSec <= windowEnd;
    windowRows = trialBouts(mask, :);
    if isempty(windowRows)
        continue;
    end
    nUnitary = sum(windowRows.isUnitaryBout);
    nCompound = sum(windowRows.isCompoundBout);
    score = min(nUnitary, nCompound) .* 10 + nUnitary + nCompound;
    if score > bestScore
        bestScore = score;
        bestMask = mask;
    end
end
bestWindow = trialBouts(bestMask, :);
end
